-- =============================================================================
-- Migration: Cargar 433 OTs históricas de camionetas Ica
-- Memphis ERP — Carga histórica Commit 5
-- Fecha: 2026-05-25
-- =============================================================================
-- RESUMEN:
--   Insertar 433 órdenes de trabajo (mantenimientos preventivos) para las 50
--   camionetas Mitsubishi L200 asignadas al proyecto GORE ICA.
--   Fuente: Excel "CONTROL DE MANTENIMIENTO DE CAMIONETAS ICA.xlsx"
--   Taller: PERUMOTOR S.A.C (concesionario Mitsubishi Ica)
--   Período: Feb 2025 - May 2026
--   Costo total terceros: S/ 151,129.22
--   Nota: costo_total es columna GENERATED, se usa costo_terceros
-- =============================================================================

BEGIN;

-- Conteo previo
DO $$
DECLARE
  v_count INT;
BEGIN
  SELECT COUNT(*) INTO v_count FROM ordenes_trabajo
  WHERE tenant_id = 'e4b16a80-8500-418e-afaa-0e976b7d9b13'
    AND numero_ot LIKE 'OT-ICA-%';
  RAISE NOTICE 'OTs Ica ANTES: %', v_count;
END $$;

-- Batch 1/18 (OTs 1-25)

-- Batch 2/18 (OTs 26-50)

-- Batch 3/18 (OTs 51-75)

-- Batch 4/18 (OTs 76-100)

-- Batch 5/18 (OTs 101-125)

-- Batch 6/18 (OTs 126-150)

-- Batch 7/18 (OTs 151-175)

-- Batch 8/18 (OTs 176-200)

-- Batch 9/18 (OTs 201-225)

-- Batch 10/18 (OTs 226-250)

-- Batch 11/18 (OTs 251-275)

