-- Batch 18/18 (OTs 426-433)
-- Verificación final
DO $$
DECLARE
  v_total INT;
  v_vehiculos INT;
  v_costo NUMERIC;
BEGIN
  SELECT COUNT(*), COUNT(DISTINCT vehiculo_id), SUM(costo_terceros)
  INTO v_total, v_vehiculos, v_costo
  FROM ordenes_trabajo
  WHERE tenant_id = 'e4b16a80-8500-418e-afaa-0e976b7d9b13'
    AND numero_ot LIKE 'OT-ICA-%';

  RAISE NOTICE '========================================';
  RAISE NOTICE 'VERIFICACIÓN COMMIT 5';
  RAISE NOTICE '========================================';
  RAISE NOTICE 'Total OTs Ica: % (esperado: 433)', v_total;
  RAISE NOTICE 'Vehículos distintos: % (esperado: 50)', v_vehiculos;
  RAISE NOTICE 'Costo total terceros: %', v_costo;
  RAISE NOTICE '========================================';

  IF v_total != 433 THEN
    RAISE EXCEPTION 'ERROR: Se esperaban 433 OTs, hay %!', v_total;
  END IF;
END $$;

COMMIT;
